   184→/** Detects the customer's preferred language from any text (name, address, etc.) */
   185→export function detectLangFromText(text: string): "ar" | "en" {
   186→  if (!text) return "ar";
   187→  const s = String(text).replace(/\s+/g, "");
   188→  if (!s) return "ar";
   189→  let ar = 0, en = 0;
   190→  for (const ch of s) {
   191→    const c = ch.charCodeAt(0);
   192→    if (c >= 0x0600 && c <= 0x06ff) ar++;
   193→    else if ((c >= 0x41 && c <= 0x5a) || (c >= 0x61 && c <= 0x7a)) en++;
   194→  }
   195→  return ar >= en ? "ar" : "en";
